schema = make_executable_schema(type_defs, query, user, post)


async def get_context_value(request):
    current_user = getattr(request.scope.get("state"), "current_user", None)
    if current_user is None:
        current_user = request.scope.get("current_user")
    return {"request": request, "current_user": current_user}


